package com.noor.alhidayah.data.repository
import com.noor.alhidayah.data.model.PrayerTime;import kotlinx.coroutines.Dispatchers;import kotlinx.coroutines.withContext
import org.json.JSONObject;import java.net.HttpURLConnection;import java.net.URL;import java.text.SimpleDateFormat;import java.util.*;import javax.inject.*
@Singleton class PrayerTimesRepository @Inject constructor(){
    suspend fun getPrayerTimes(latitude:Double,longitude:Double):Result<List<PrayerTime>>=withContext(Dispatchers.IO){try{val date=SimpleDateFormat("dd-MM-yyyy",Locale.US).format(Date());val url=URL("https://api.aladhan.com/v1/timings/$date?latitude=$latitude&longitude=$longitude&method=4");val conn=url.openConnection() as HttpURLConnection;conn.connectTimeout=10000;conn.readTimeout=10000;val resp=conn.inputStream.bufferedReader().readText();val j=JSONObject(resp);if(j.getInt("code")==200){val t=j.getJSONObject("data").getJSONObject("timings");Result.success(parsePrayerTimes(t))}else Result.failure(Exception("API error"))}catch(e:Exception){Result.failure(e)}}
    private fun parsePrayerTimes(t:JSONObject):List<PrayerTime>{val now=Calendar.getInstance();val prayers=listOf(PrayerTime("Fajr","\u0627\u0644\u0641\u062c\u0631",t.getString("Fajr").take(5),0),PrayerTime("Dhuhr","\u0627\u0644\u0638\u0647\u0631",t.getString("Dhuhr").take(5),0),PrayerTime("Asr","\u0627\u0644\u0639\u0635\u0631",t.getString("Asr").take(5),0),PrayerTime("Maghrib","\u0627\u0644\u0645\u063a\u0631\u0628",t.getString("Maghrib").take(5),0),PrayerTime("Isha","\u0627\u0644\u0639\u0634\u0627\u0621",t.getString("Isha").take(5),0));return prayers.map{p->val parts=p.time.split(":");val pc=Calendar.getInstance().apply{set(Calendar.HOUR_OF_DAY,parts[0].toInt());set(Calendar.MINUTE,parts[1].toInt());set(Calendar.SECOND,0);set(Calendar.MILLISECOND,0)};val millis=pc.timeInMillis;val rem=if(millis>now.timeInMillis) (millis-now.timeInMillis)/1000 else (millis+86400000-now.timeInMillis)/1000;p.copy(timeInMillis=millis,remainingSeconds=rem)}.let{pt->val next=pt.filter{it.remainingSeconds>0}.minByOrNull{it.remainingSeconds};pt.map{it.copy(isNext=it.name==next?.name)}}}
}